# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
import json
from kafka.admin import KafkaAdminClient, NewTopic
from kafka.errors import TopicAlreadyExistsError, NoBrokersAvailable

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config_entries):
    new_topic = NewTopic(name=topic_name, num_partitions=num_partitions,
                         replication_factor=replication_factor, topic_configs=config_entries)
    try:
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully with {num_partitions} partitions and replication factor {replication_factor}.")
        if config_entries:
            print(f"  Configuration: {config_entries}")
        return True
    except TopicAlreadyExistsError:
        print(f"Warning: Topic '{topic_name}' already exists.")
        return False
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")
        return False

def alter_topic_partitions(admin_client, topic_name, new_num_partitions):
    try:
        admin_client.create_partitions(topic_partitions_counts={topic_name: new_num_partitions})
        print(f"Topic '{topic_name}' partitions updated to {new_num_partitions}.")
        return True
    except Exception as e:
        print(f"Error altering partitions for topic '{topic_name}': {e}")
        return False

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics(topics=[topic_name])
        print(f"Topic '{topic_name}' deleted successfully.")
        return True
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")
        return False

def describe_topics(admin_client, topic_names=None):
    try:
        topics_info = admin_client.describe_topics(topic_names=topic_names)
        if not topics_info:
            print("No topics found or specified.")
            return

        for topic in topics_info:
            print(f"\nTopic Name: {topic.name}")
            print(f"  Partitions: {len(topic.partitions)}")
            print(f"  Replication Factor: {len(topic.partitions[0].replicas) if topic.partitions else 'N/A'}")
            print("  Partition Details:")
            for p in topic.partitions:
                print(f"    Partition {p.id}: Leader={p.leader}, Replicas={p.replicas}, ISR={p.isr}")
            # Note: describe_topics does not directly return topic_configs.
            # To get configs, you would need to use `admin_client.describe_configs`
            # and specify the config type as `ConfigResourceType.TOPIC`.
            # This example focuses on basic topic metadata.
        return True
    except Exception as e:
        print(f"Error describing topics: {e}")
        return False

def describe_topic_configs(admin_client, topic_name):
    from kafka.admin import ConfigResource, ConfigResourceType
    try:
        config_resources = [ConfigResource(ConfigResourceType.TOPIC, topic_name)]
        configs = admin_client.describe_configs(config_resources)
        print(f"\nConfiguration for Topic '{topic_name}':")
        if configs:
            for resource, config_entries in configs.items():
                for entry in config_entries:
                    print(f"  {entry.name}: {entry.value}")
        else:
            print("  No specific configurations found or topic does not exist.")
        return True
    except Exception as e:
        print(f"Error describing topic configs for '{topic_name}': {e}")
        return False


def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Script using kafka-python AdminClient.")
    parser.add_argument("--bootstrap-servers", default="localhost:9092",
                        help="Comma-separated list of Kafka bootstrap servers (e.g., 'host1:9092,host2:9092').")

    subparsers = parser.add_subparsers(dest="command", required=True, help="Available commands")

    # Create Topic command
    parser_create = subparsers.add_parser("create", help="Create a new Kafka topic.")
    parser_create.add_argument("--name", required=True, help="Name of the topic to create.")
    parser_create.add_argument("--partitions", type=int, default=1,
                               help="Number of partitions for the new topic.")
    parser_create.add_argument("--replication-factor", type=int, default=1,
                               help="Replication factor for the new topic.")
    parser_create.add_argument("--config", type=json.loads, default="{}",
                               help="JSON string of topic configuration entries (e.g., '{\"retention.ms\": \"604800000\"}').")

    # Alter Partitions command
    parser_alter_partitions = subparsers.add_parser("alter-partitions", help="Alter the number of partitions for an existing topic.")
    parser_alter_partitions.add_argument("--name", required=True, help="Name of the topic to alter.")
    parser_alter_partitions.add_argument("--new-partitions", type=int, required=True,
                                         help="New number of partitions for the topic. Must be greater than current.")

    # Delete Topic command
    parser_delete = subparsers.add_parser("delete", help="Delete an existing Kafka topic.")
    parser_delete.add_argument("--name", required=True, help="Name of the topic to delete.")

    # Describe Topics command
    parser_describe = subparsers.add_parser("describe", help="Describe existing Kafka topics.")
    parser_describe.add_argument("--name", nargs='*', help="Specific topic names to describe (optional). If omitted, describes all topics.")
    parser_describe.add_argument("--configs", action="store_true", help="Also describe topic configurations.")


    args = parser.parse_args()

    try:
        admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
    except NoBrokersAvailable:
        print(f"Error: Could not connect to Kafka brokers at {args.bootstrap_servers}. Please check your connection and broker status.")
        return
    except Exception as e:
        print(f"An unexpected error occurred during AdminClient initialization: {e}")
        return

    try:
        if args.command == "create":
            create_topic(admin_client, args.name, args.partitions, args.replication_factor, args.config)
        elif args.command == "alter-partitions":
            alter_topic_partitions(admin_client, args.name, args.new_partitions)
        elif args.command == "delete":
            delete_topic(admin_client, args.name)
        elif args.command == "describe":
            if args.name:
                for topic_name in args.name:
                    describe_topics(admin_client, topic_names=[topic_name])
                    if args.configs:
                        describe_topic_configs(admin_client, topic_name)
            else:
                # Describe all topics
                describe_topics(admin_client)
                if args.configs:
                    print("\nWarning: --configs flag is typically used with specific topic names for detailed configuration. "
                          "Listing configs for all topics might be verbose. Skipping full config dump for all topics.")

    finally:
        admin_client.close()

if __name__ == "__main__":
    main()